// Single source of truth for user-facing AI model entries.
//
// Each entry is identified by its `id` (`recommended`, `frontier:openai`,
// `balanced`, `balanced:anthropic`, `balanced:xai`, `fast`, `fast:google`). A bare
// tier id like `balanced` is the tier's default backing model; ids of the
// form `<tier>:<provider>` pin that tier to a specific provider. When a
// pinned id is removed, `resolveModelId` falls back to the bare tier default.
// The
// `gatewayModelId` is the bare upstream slug used by the AI gateway
// (e.g. `anthropic/claude-opus-4.8`). The agent-gateway adds any proxy
// prefix when forwarding to the runner.
//
// All ids are aggregate roles that resolve to a concrete provider
// internally, so cron jobs and saved defaults can pin a *role* instead of a
// specific weights revision and survive model upgrades without migration.

export type ModelProvider =
  | 'anthropic'
  | 'openai'
  | 'xai'
  | 'moonshotai'
  | 'google'
  | 'deepseek'
  | 'zai'

/** Upstream gateway slug, e.g. `anthropic/claude-opus-4.8`. */
export type GatewayModelId = `${ModelProvider}/${string}`

export type ModelId =
  | 'recommended'
  | 'frontier:openai'
  | 'balanced'
  | 'balanced:anthropic'
  | 'balanced:xai'
  | 'fast'
  | 'fast:google'

export type ModelPricing = {
  inputTokensPer1M: number // $ per 1M input tokens
  outputTokensPer1M: number // $ per 1M output tokens
  cachedInputTokensPer1M: number // $ per 1M cached input tokens
}

export type AiModelDefinition = {
  /** Stable identifier used everywhere (cron configs, persisted rows, UI). */
  id: ModelId
  gatewayModelId: GatewayModelId
  name: string
  simpleName: string
  description: string
  speed: 1 | 2 | 3 | 4 | 5 // 1 = slowest, 5 = fastest
  intelligence: 1 | 2 | 3 | 4 | 5 // 1 = basic, 5 = most capable
  enabled: boolean
  pricing: ModelPricing
  /**
   * Promotional override: when true, Duet absorbs the cost of this model and
   * users are never debited for it (token-cost calc returns 0, gateway
   * reconciliation skips the ledger debit, and the picker shows a "Free"
   * badge). Duet still pays the upstream provider via the AI gateway — this
   * flag only controls user-visible charging.
   */
  isFree?: boolean
  /**
   * When set, force Duet's AI-gateway proxy to route this model only to these
   * upstream providers, in this order, overriding any caller-supplied routing.
   * e.g. GLM-4.7 is locked to `['cerebras']`.
   */
  providerLock?: string[]
}

/**
 * Duet's user-facing model catalogue.
 *
 * `recommended` is the default — the strongest available model. The
 * `balanced:*` roles target a strong cost/quality tradeoff, and `fast:*`
 * is the speed-oriented aggregate. Each description names the exact
 * upstream model currently backing the role.
 */
export const AI_MODELS: AiModelDefinition[] = [
