export const DEFAULT_MODEL_ID: ModelId = 'recommended'

export function getModelById(id: string | undefined): AiModelDefinition | undefined {
  if (!id) return undefined
  return AI_MODELS.find(m => m.id === id)
}

export function isModelEnabled(id: string | undefined): boolean {
  return getModelById(id)?.enabled === true
}

/**
 * Resolve the effective model id for a caller. Cron jobs and saved org
 * defaults flow through this so model rotations never require migration.
 *
 * Resolution order when `saved` is missing, disabled, or unknown:
 *   1. If `saved` is a provider-pinned tier id (`<tier>:<provider>`, e.g.
 *      `balanced:xai`) and the bare tier default (`balanced`) is enabled,
 *      fall back to that tier default. So removing `xai` quietly moves
 *      everyone on `balanced:xai` to whatever currently backs `balanced`.
 *   2. Otherwise fall back to {@link DEFAULT_MODEL_ID}.
 */
export function resolveModelId(saved: string | undefined): ModelId {
  if (!saved) return DEFAULT_MODEL_ID
  const model = getModelById(saved)
  if (model?.enabled) return model.id

  // Saved id is missing or disabled. If it pinned a tier to a specific
  // provider (`<tier>:<provider>`), prefer that tier's bare default before
  // dropping to the global default.
  const tier = saved.split(':')[0]
  if (tier && tier !== saved) {
    const tierDefault = getModelById(tier)
    if (tierDefault?.enabled) return tierDefault.id
  }

  return DEFAULT_MODEL_ID
}

/**
 * Infer the provider for a model from its gateway slug. Used by the picker UI
 * to render the right provider icon without grepping ids at the call site.
 */
export function getModelProvider(id: string | undefined): ModelProvider | undefined {
  const def = getModelById(id)
  if (!def) return undefined
  return def.gatewayModelId.split('/')[0] as ModelProvider
}

export function getModelPricing(id: string | undefined): ModelPricing | undefined {
  return getModelById(id)?.pricing
}

/** True when the model is currently promo-free for end users. */
export function isModelFree(id: string | undefined): boolean {
  return getModelById(id)?.isFree === true
}

/**
 * Upstream gateway slugs that any caller may invoke without paying, even
 * though they are not part of the user-facing {@link AI_MODELS} chat-model
 * catalogue. Two groups live here:
 *
 * 1. Infrastructure models Duet relies on internally — e.g. the embedding
 *    model and cheap utility model that duet-agent calls directly.
 * 2. The image & video generation models the default sandbox skills (the
 *    `media-creation` skill) actively recommend to users. Trial users
 *    routinely generate images/video through these, so they must not be
 *    gated behind the payment check or we'd auto-pause legitimate trial
 *    usage. Keep this list in sync with `media-creation/SKILL.md` and its
 *    references.
 *
 * Neither group is part of {@link AI_MODELS}, so they must be whitelisted
 * explicitly.
 */
export const WHITELISTED_GATEWAY_MODEL_IDS: ReadonlySet<string> = new Set([
  // Infrastructure models called directly by duet-agent.
  'openai/gpt-5.4-mini',
  'google/gemini-embedding-2',
  // Image models recommended by the media-creation skill.
  'openai/gpt-image-2',
  'openai/gpt-image-1.5',
  'google/gemini-3.1-flash-image-preview',
  // Video models recommended by the media-creation skill.
  'bytedance/seedance-2.0-fast',
  'bytedance/seedance-2.0',
  'google/veo-3.0-generate-001',
  'klingai/kling-v3.0-t2v',
  'klingai/kling-v3.0-i2v',
])

/**
 * The upstream gateway slugs (e.g. `anthropic/claude-opus-4.8`) that any
 * caller may invoke through the public AI-gateway proxy without having paid:
 * the enabled entries in {@link AI_MODELS}. Models outside this set (and the
 * {@link WHITELISTED_GATEWAY_MODEL_IDS}) are gated behind a prior payment.
 */
export function getAllowedGatewayModelIds(): Set<GatewayModelId> {
  return new Set(AI_MODELS.filter(m => m.enabled).map(m => m.gatewayModelId))
}

/**
 * True when `gatewaySlug` may be invoked by any caller without having paid:
 * either an enabled entry in {@link AI_MODELS} or an infrastructure model on
 * {@link WHITELISTED_GATEWAY_MODEL_IDS}. Any other model is only allowed for
 * orgs that have paid before.
 */
export function isGatewayModelAllowed(gatewaySlug: string | undefined): boolean {
  if (!gatewaySlug) return false
  return (
    WHITELISTED_GATEWAY_MODEL_IDS.has(gatewaySlug) ||
    getAllowedGatewayModelIds().has(gatewaySlug as GatewayModelId)
  )
}

/**
 * Same as {@link isModelFree} but keyed off the upstream gateway slug
 * (e.g. `xai/grok-4.3`). The AI-gateway reconciliation path receives the
 * gateway slug — not Duet's internal role id — when crediting usage, so we
 * need this lookup to decide whether to skip the ledger debit.
 */
export function isGatewayModelFree(gatewaySlug: string | undefined): boolean {
  if (!gatewaySlug) return false
  return AI_MODELS.some(m => m.gatewayModelId === gatewaySlug && m.isFree === true)
}

/**
 * Prefix the duet-agent runner uses to route a model through Duet's AI-gateway
 * provider. A model stored for the runner (a session default or a per-state
 * override) is kept in this `duet:<gatewaySlug>` form so the runner's
 * `resolveModelName` resolves it through the same gateway path.
 */
export const DUET_RUNNER_MODEL_PREFIX = 'duet:'

/**
 * Normalize a user- or API-supplied model string to the runner-native
 * `duet:<gatewaySlug>` form, or return `null` when the value is not an
 * accepted, enabled model.
 *
 * Accepts any of: a user-facing {@link ModelId} (e.g. `"recommended"`), the
 * gateway slug of an enabled entry (e.g. `"anthropic/claude-opus-4.8"`), or an
 * already normalized `"duet:<gatewaySlug>"` value — so a value read back from
 * storage round-trips cleanly.
 *
 * The accepted set is exactly the enabled {@link AI_MODELS} catalogue — the
 * same models offered in the UI. Infrastructure/image/video models on
 * {@link WHITELISTED_GATEWAY_MODEL_IDS} are intentionally rejected: if a user
 * cannot pick it in the UI, it cannot be set programmatically either.
 */
export function normalizeRunnerModelId(model: string): string | null {
  const slug = model.startsWith(DUET_RUNNER_MODEL_PREFIX)
    ? model.slice(DUET_RUNNER_MODEL_PREFIX.length)
    : (getModelById(model)?.gatewayModelId ?? model)
  return getAllowedGatewayModelIds().has(slug as GatewayModelId)
    ? `${DUET_RUNNER_MODEL_PREFIX}${slug}`
    : null
}

/** The enabled, user-selectable Duet model ids (e.g. `recommended`, `balanced`). */
export function getEnabledModelIds(): ModelId[] {
  return AI_MODELS.filter(m => m.enabled).map(m => m.id)
}

/**
 * Build a validation error message for a rejected `model`, listing the accepted
 * Duet model ids so the caller can correct it without guessing.
 */
export function invalidModelMessage(model: string): string {
  return (
    `Unknown or disallowed model "${model}". Valid models: ${getEnabledModelIds().join(', ')} ` +
    `(a "duet:<gatewaySlug>" value as returned by the API for one of these is also accepted).`
  )
}

/**
 * The `{ only, order }` gateway routing for a slug, derived from the model
 * entry's {@link AiModelDefinition.providerLock}, or `undefined` when the model
 * is not locked to specific providers.
 */
export function getGatewayProviderLock(
  gatewaySlug: string | undefined,
): { only: string[]; order: string[] } | undefined {
  if (!gatewaySlug) return undefined
  const lock = AI_MODELS.find(m => m.gatewayModelId === gatewaySlug)?.providerLock
  if (!lock || lock.length === 0) return undefined
  return { only: lock, order: lock }
}

function getBlendedPrice(pricing: ModelPricing): number {
  return pricing.inputTokensPer1M + pricing.outputTokensPer1M
}

export function getModelCostRating(model: AiModelDefinition): 0 | 1 | 2 | 3 | 4 | 5 {
  if (model.isFree) return 0

  const prices = AI_MODELS.map(m => getBlendedPrice(m.pricing))
  const min = Math.min(...prices)
  const max = Math.max(...prices)
  if (max === min) return 3
  const normalized = (getBlendedPrice(model.pricing) - min) / (max - min)
  const rating = Math.round(1 + normalized * 4)
  return Math.max(1, Math.min(5, rating)) as 1 | 2 | 3 | 4 | 5
}

