import { describe, expect, it } from 'vitest'

import {
  AI_MODELS,
  DEFAULT_MODEL_ID,
  getEnabledModelIds,
  getGatewayProviderLock,
  getModelById,
  getModelCostRating,
  invalidModelMessage,
  isGatewayModelAllowed,
  normalizeRunnerModelId,
  resolveModelId,
  WHITELISTED_GATEWAY_MODEL_IDS,
} from './ai-models'

describe('getModelCostRating', () => {
  // Synthesize models off a real entry so the assertions exercise the
  // `isFree` short-circuit directly, independent of whatever the live
  // catalogue happens to mark as free.
  const basis = AI_MODELS[0]!

  it('returns 0 for promo-free models regardless of upstream pricing', () => {
    expect(getModelCostRating({ ...basis, isFree: true })).toBe(0)
  })

  it('returns a positive score for paid models', () => {
    expect(getModelCostRating({ ...basis, isFree: false })).toBeGreaterThan(0)
  })
})

describe('resolveModelId', () => {
  it('keeps an enabled saved id as-is', () => {
    expect(resolveModelId('balanced:xai')).toBe('balanced:xai')
  })

  it('falls back to the global default when saved is missing', () => {
    expect(resolveModelId(undefined)).toBe(DEFAULT_MODEL_ID)
  })

  it('falls back to the bare tier default when a provider-pinned id is gone', () => {
    // `balanced:foo` is not in the catalogue; the `balanced` tier default is.
    expect(resolveModelId('balanced:foo')).toBe('balanced')
    expect(AI_MODELS.some(m => m.id === 'balanced' && m.enabled)).toBe(true)
  })
})

describe('normalizeRunnerModelId', () => {
  it('normalizes a user-facing model id to the runner-native duet: form', () => {
    expect(normalizeRunnerModelId('recommended')).toBe(
      `duet:${getModelById('recommended')!.gatewayModelId}`,
    )
  })

  it('normalizes a bare allowed gateway slug', () => {
    const slug = getModelById('recommended')!.gatewayModelId
    expect(normalizeRunnerModelId(slug)).toBe(`duet:${slug}`)
  })

  it('round-trips an already-normalized duet:<slug> value', () => {
    const slug = getModelById('balanced:anthropic')!.gatewayModelId
    expect(normalizeRunnerModelId(`duet:${slug}`)).toBe(`duet:${slug}`)
  })

  it('returns null for an unknown model id', () => {
    expect(normalizeRunnerModelId('gpt-make-believe-9')).toBeNull()
  })

  it('returns null for a disallowed gateway slug', () => {
    expect(normalizeRunnerModelId('acme/not-a-real-model')).toBeNull()
  })

  it('rejects whitelisted infra/image/video models that the UI never offers', () => {
    // `openai/gpt-image-2` is invocable through the gateway proxy but is not an
    // AI_MODELS entry, so it must not be settable as a kanban column model.
    expect(normalizeRunnerModelId('openai/gpt-image-2')).toBeNull()
  })

  it('returns null for a duet: prefix wrapping a disallowed slug', () => {
    expect(normalizeRunnerModelId('duet:acme/not-a-real-model')).toBeNull()
  })

  it('accepts every enabled catalogue id', () => {
    for (const id of getEnabledModelIds()) {
      expect(normalizeRunnerModelId(id)).toBe(`duet:${getModelById(id)!.gatewayModelId}`)
    }
  })
})

describe('invalidModelMessage', () => {
  it('names the offending value and lists every enabled model id', () => {
    const message = invalidModelMessage('bogus-model')
    expect(message).toContain('"bogus-model"')
    for (const id of getEnabledModelIds()) {
      expect(message).toContain(id)
    }
  })
})

