/**
 * Minimum `@duetso/agent` version a sandbox must be running before the
 * gateway will serve turns against it. The package ships the `duet --rpc`
 * binary the gateway spawns per turn, so when a gateway change breaks the
 * wire contract with an older runner we raise this floor and any sandbox
 * that comes up cold below it is force-upgraded (through the gateway, to
 * latest) before phase 2 starts the gateway.
 *
 * This is meant to be edited in place on each breaking bump — it is NOT a
 * versioned init step, so raising it re-gates every sandbox on its next
 * cold setup without minting a new id or running a migration. Keep it in
 * sync with the `@duetso/agent` floor in
 * `packages/{agent-gateway,backend}/package.json`.
 */
// 0.1.189 is the first runner release that can resolve anthropic/claude-fable-5
// (the frontier:anthropic catalogue entry); older bundles silently fall back to
// their opus-4.8 default.
const MIN_DUET_VERSION = '0.1.189'

const CREDENTIALS_PATH = `${SANDBOX_HOME_DIR}/.duet/credentials.json`
const ENV_FILE_PATH = SANDBOX_ENV_FILE_PATH
const DUET_DIR = `${SANDBOX_HOME_DIR}/.duet`
const GATEWAY_PATH = `${DUET_DIR}/gateway.js`
const GATEWAY_LOG_PATH = `${DUET_DIR}/gateway.log`
const GATEWAY_WATCHDOG_SCRIPT = `${DUET_DIR}/gateway-watchdog.sh`

export interface SetupGatewayReason {
  source:
    | 'sandbox-created'
    | 'sandbox-recreated'
    | 'gateway-health-idle'
    | 'gateway-health-check-failed'
  detail?: string
  healthActiveRunners?: number
/**
 * Upload the gateway binary to a sandbox.
 *
 * ETag check makes this idempotent — only re-downloads when the blob has changed.
 */
async function doUploadGateway({
  sandbox,
}: {
  sandbox: E2BSandbox
}): Promise<{ binaryChanged: boolean }> {
  // Each Convex deployment auto-namespaces its own gateway bundle via
  // ConvexDeploymentName (same pattern as the mixbread message store).
  if (!ConvexDeploymentName) {
    throw new Error('CONVEX_DEPLOYMENT is not set; cannot resolve gateway bundle path')
  }
  const blobPath = getSandboxGatewayBlobPath(ConvexDeploymentName)
  const blobUrl = `${SANDBOX_BLOB_STORE_URL}/${blobPath}`
  console.info('Resolving gateway bundle', { deployment: ConvexDeploymentName, blobUrl })
  const [remoteEtag, existingEtag] = await Promise.all([
    fetchBlobEtag(blobUrl),
    getGatewayEtag({ sandbox }),
  ])

  if (existingEtag !== remoteEtag) {
    console.info('Gateway ETag differs, uploading binary', {
      existingEtag,
      remoteEtag,
    })
    await uploadGatewayBinary({
      sandbox,
      downloadUrl: blobUrl,
      etag: remoteEtag,
    })
    return { binaryChanged: !!existingEtag }
  }

  console.info('Gateway ETag matches, skipping upload', { etag: remoteEtag })
  return { binaryChanged: false }
}

