      // duet-gateway provider path in the runner's `resolveModelName`.
      const normalized = normalizeRunnerModelId(args.model)
      assert(normalized, invalidModelMessage(args.model))
      nextState.model = normalized
    }
  }
  if (args.thinkingLevel !== undefined) {
    if (args.thinkingLevel === null) {
      delete nextState.thinkingLevel
    } else {
      nextState.thinkingLevel = args.thinkingLevel
    }
  }

  const nextStates = [...states]
  nextStates[index] = nextState
  await ctx.db.patch('channels', args.channelId, {
    kanbanDefinition: { ...channel.kanbanDefinition, states: nextStates },
    updatedAt: Date.now(),
  })
}

