/**
 * Translate a board definition's per-state model overrides from their stored
 * form to the runner-native `duet:<gatewaySlug>` the gateway forwards untouched.
 *
 * `setKanbanStateModel` now persists the aggregate role id (e.g.
 * `frontier:anthropic`), but rows written before that change hold a pinned
 * `duet:<gatewaySlug>` value. `normalizeRunnerModelId` accepts a role id, a bare
 * gateway slug, or an already-`duet:`-prefixed value, so both old and new
 * storage translate here with no migration. A model that no longer resolves to
 * an enabled catalogue entry is dropped (state inherits the parent runner's
 * model) rather than forwarding a dead slug.
 *
 * This is the single boundary where role -> gateway-slug translation happens for
 * board models: the backend deploys atomically with the catalogue, so the
 * mapping is always fresh, and the gateway never needs the catalogue itself.
 */
export function toRunnerKanbanDefinition(
  definition: StateMachineDefinition,
): StateMachineDefinition {
  return {
    ...definition,
    states: definition.states.map(state => {
      if (state.kind !== 'agent' || state.model === undefined) return state
      const runnerModel = normalizeRunnerModelId(state.model)
      if (runnerModel === null) {
        const { model: _dropped, ...rest } = state
        return rest
      }
      return { ...state, model: runnerModel }
    }),
  }
}

