export function toRunnerKanbanDefinition(
  definition: StateMachineDefinition,
): StateMachineDefinition {
  // The persisted definition validates `states` as `v.any()`, and the
  // `@duetso/agent` `StateMachineAgentState` the backend resolves doesn't
  // expose `model`, so read the per-state model structurally.
  type KanbanState = StateMachineDefinition['states'][number]
  return {
    ...definition,
    states: definition.states.map((state): KanbanState => {
      const candidate = state as { kind?: unknown; model?: unknown }
      if (candidate.kind !== 'agent' || typeof candidate.model !== 'string') return state
      const runnerModel = normalizeRunnerModelId(candidate.model)
      const next = { ...(state as Record<string, unknown>) }
      if (runnerModel === null) {
        delete next.model
      } else {
        next.model = runnerModel
      }
      return next as KanbanState
    }),
  }
}

